"\n"
"<script>\n"
"var REFRESH_INTERVAL=5000,countdown=REFRESH_INTERVAL/1000,errorCount=0;\n"
"function fmtMB(b){return b>=1073741824?(b/1073741824).toFixed(2)+' GB':(b/1048576).toFixed(0)+' MB'}\n"
"function fmtSec(s){var h=Math.floor(s/3600),m=Math.floor((s%3600)/60);return h>0?h+'h '+m+'m':m+'m '+s%60+'s'}\n"
"\n"
"function drawGauge(cid,pct,color){\n"
"var c=document.getElementById(cid);if(!c)return;\n"
"var ctx=c.getContext('2d'),w=c.width,h=c.height,cx=w/2,cy=h/2,r=55,lw=10;\n"
"ctx.clearRect(0,0,w,h);\n"
"ctx.beginPath();ctx.arc(cx,cy,r,0.75*Math.PI,2.25*Math.PI);ctx.strokeStyle='#21262d';ctx.lineWidth=lw;ctx.stroke();\n"
"if(pct>0){ctx.beginPath();var sa=0.75*Math.PI,sw=pct/100*1.5*Math.PI;ctx.arc(cx,cy,r,sa,sa+sw);ctx.strokeStyle=color;ctx.lineWidth=lw;ctx.lineCap='round';ctx.stroke();}\n"
"ctx.fillStyle='#e6edf3';ctx.font='bold 22px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(pct+'%',cx,cy-2);\n"
"}\n"
"\n"
"function drawHistory(data){\n"
"var c=document.getElementById('chart-history');if(!c||!data||!data.points||data.points.length<2)return;\n"
"var p=c.parentElement;c.width=p.clientWidth-4;c.height=p.clientHeight-4;\n"
"var ctx=c.getContext('2d'),w=c.width,h=c.height;\n"
"ctx.clearRect(0,0,w,h);\n"
"var pad={top:20,right:40,bottom:30,left:50},pw=w-pad.left-pad.right,ph=h-pad.top-pad.bottom;\n"
"var pts=data.points;\n"
"function px(i){return pad.left+(pw*(i/(pts.length-1)))}\n"
"function py(v){return pad.top+ph-(ph*(v/100))}\n"
"ctx.fillStyle='#8b949e';ctx.font='11px Segoe UI';\n"
"for(var v=0;v<=100;v+=20){var y=py(v);ctx.fillText(v+'%',4,y+4);ctx.beginPath();ctx.moveTo(pad.left,y);ctx.lineTo(pad.left+pw,y);ctx.strokeStyle='#21262d';ctx.stroke();}\n"
"for(var i=0;i<pts.length;i+=Math.max(1,Math.floor(pts.length/6))){var d=new Date(pts[i].t*1000);ctx.fillText(d.getHours().toString().padStart(2,'0')+':'+d.getMinutes().toString().padStart(2,'0'),px(i)-15,h-4);}\n"
"ctx.beginPath();for(var i=0;i<pts.length;i++){var x=px(i),y=py(pts[i].pf);i==0?ctx.moveTo(x,y):ctx.lineTo(x,y);}ctx.strokeStyle='#58a6ff';ctx.lineWidth=2;ctx.stroke();\n"
"ctx.beginPath();for(var i=0;i<pts.length;i++){var x=px(i),y=py(pts[i].ph);i==0?ctx.moveTo(x,y):ctx.lineTo(x,y);}ctx.strokeStyle='#3fb950';ctx.lineWidth=2;ctx.setLineDash([4,4]);ctx.stroke();ctx.setLineDash([]);\n"
"ctx.fillStyle='#58a6ff';ctx.fillRect(pad.left+10,8,12,12);ctx.fillStyle='#3fb950';ctx.fillRect(pad.left+80,8,12,12);ctx.fillStyle='#e6edf3';ctx.textAlign='left';ctx.fillText('Page File',pad.left+26,18);ctx.fillText('Physical',pad.left+96,18);\n"
"}\n"
"\n"
"function updProcesses(procs){\n"
"var tb=document.getElementById('process-tbody'),s=document.getElementById('proc-search').value.toLowerCase();\n"
"tb.innerHTML='';var n=0;\n"
"for(var i=0;i<procs.length;i++){var p=procs[i];if(s&&p.name.toLowerCase().indexOf(s)<0)continue;\n"
"var cls=p.commit_mb>2048?'danger':p.commit_mb>512?'warning':'';\n"
"tb.innerHTML+='<tr><td>'+(n+1)+'</td><td>'+p.pid+'</td><td class=\"process-name\" title=\"'+p.name+'\">'+p.name+'</td><td class=\"'+cls+'\">'+(p.commit_mb>1024?(p.commit_mb/1024).toFixed(2)+' GB':p.commit_mb+' MB')+'</td><td>'+(p.ws_mb>1024?(p.ws_mb/1024).toFixed(2)+' GB':p.ws_mb+' MB')+'</td></tr>';n++;}\n"
"if(!n)tb.innerHTML='<tr><td colspan=\"5\" style=\"text-align:center;color:#8b949e\">No matching processes</td></tr>';\n"
"}\n"
"\n"
"function updActions(acts){\n"
"var d=document.getElementById('action-log');\n"
"if(!acts||!acts.length){d.innerHTML='<div class=\"log-entry\"><span class=\"log-msg\" style=\"color:#8b949e\">No actions recorded</span></div>';return}\n"
"d.innerHTML='';\n"
"for(var i=0;i<acts.length;i++){var a=acts[i],dt=new Date(a.t*1000),ts=dt.getHours().toString().padStart(2,'0')+':'+dt.getMinutes().toString().padStart(2,'0')+':'+dt.getSeconds().toString().padStart(2,'0');\n"
"var delta=a.bf-a.af,ds=delta>0?'<span class=\"success\">-'+delta+'%</span>':(delta<0?'<span class=\"warning\">+'+Math.abs(delta)+'%</span>':'unchanged');\n"
"d.innerHTML+='<div class=\"log-entry\"><span class=\"log-time\">'+ts+'</span><span class=\"log-msg\">Trimmed <b>'+a.tc+'</b> procs, '+a.fc+' failed | PF: '+a.bf+'% &rarr; '+a.af+'% '+ds+'</span></div>';}\n"
"}\n"
"\n"
"function updStatus(s){\n"
"document.getElementById('uptime').textContent=fmtSec(s.running_seconds);\n"
"document.getElementById('sys-total-phys').textContent=fmtMB(s.total_phys_mb*1048576);\n"
"document.getElementById('sys-avail-phys').textContent=fmtMB(s.avail_phys_mb*1048576);\n"
"document.getElementById('sys-total-pf').textContent=fmtMB(s.total_pagefile_mb*1048576);\n"
"document.getElementById('sys-avail-pf').textContent=fmtMB(s.avail_pagefile_mb*1048576);\n"
"document.getElementById('sys-idle').textContent=fmtSec(s.idle_seconds);\n"
"var pfc=s.page_file_pct>85?'#f85149':s.page_file_pct>60?'#d29922':'#3fb950';\n"
"var phc=s.phys_load>90?'#f85149':s.phys_load>70?'#d29922':'#3fb950';\n"
"drawGauge('gauge-pf',s.page_file_pct,pfc);drawGauge('gauge-phys',s.phys_load,phc);\n"
"document.getElementById('gauge-pf-pct').textContent=s.page_file_pct+'%';document.getElementById('gauge-pf-pct').style.color=pfc;\n"
"document.getElementById('gauge-phys-pct').textContent=s.phys_load+'%';document.getElementById('gauge-phys-pct').style.color=phc;\n"
"updProcesses(s.processes||[]);\n"
"document.getElementById('status-dot').style.background=s.page_file_pct>=s.threshold_pct?'#d29922':'#3fb950';\n"
"errorCount=0;\n"
"}\n"
"\n"
"function fetchStatus(){fetch('/api/status').then(function(r){if(!r.ok)throw Error('HTTP '+r.status);return r.json()}).then(updStatus).catch(function(e){errorCount++;if(errorCount>=3){document.getElementById('error-banner').style.display='block';document.getElementById('error-banner').textContent='Cannot connect to backend (error: '+e.message+')';}})}\n"
"function fetchHistory(){fetch('/api/history').then(function(r){return r.json()}).then(drawHistory).catch(function(){})}\n"
"function fetchActions(){fetch('/api/actions').then(function(r){return r.json()}).then(function(d){updActions(d.actions||[])}).catch(function(){})}\n"
"function fetchCpu(){fetch('/api/cpu').then(function(r){return r.json()}).then(function(d){updCpu(d.processes||[])}).catch(function(){})}\n"
"function fetchGpu(){fetch('/api/gpu').then(function(r){return r.json()}).then(updGpu).catch(function(){})}\n"
"function fetchAnomalies(){fetch('/api/anomalies').then(function(r){return r.json()}).then(function(d){updAnomalies(d.alerts||[])}).catch(function(){})}\n"
"function fetchSuspicious(){fetch('/api/suspicious').then(function(r){return r.json()}).then(function(d){updSuspicious(d.processes||[])}).catch(function(){})}\n"
"\n"
"function updCpu(procs){\n"
"var tb=document.getElementById('cpu-tbody');\n"
"if(!procs.length){tb.innerHTML='<tr><td colspan=\"5\" style=\"text-align:center;color:#8b949e\">All normal (&lt;1% CPU)</td></tr>';return}\n"
"tb.innerHTML='';for(var i=0;i<procs.length;i++){var p=procs[i],cls=p.cpu_pct>50?'danger':p.cpu_pct>25?'warning':'success',st=p.consecutive>=3?'<span class=\"badge badge-danger\">ANOMALY</span>':'<span class=\"badge badge-ok\">OK</span>';tb.innerHTML+='<tr><td>'+p.pid+'</td><td class=\"process-name\" title=\"'+p.name+'\">'+p.name+'</td><td class=\"'+cls+'\">'+p.cpu_pct.toFixed(1)+'%</td><td>'+p.consecutive+'</td><td>'+st+'</td></tr>';}\n"
"}\n"
"\n"
"function updGpu(gpu){\n"
"var d=document.getElementById('gpu-info');\n"
"if(!gpu||!gpu.available){d.innerHTML='<div class=\"metric-row\"><span class=\"label\">GPU</span><span class=\"value\" style=\"color:#8b949e\">Unavailable (no dGPU or driver)</span></div>';return}\n"
"var uc=gpu.utilization>90?'danger':gpu.utilization>60?'warning':'success';\n"
"d.innerHTML='<div class=\"metric-row\"><span class=\"label\">GPU Name</span><span class=\"value\">'+gpu.name+'</span></div><div class=\"metric-row\"><span class=\"label\">Utilization</span><span class=\"value '+uc+'\">'+gpu.utilization+'%</span></div><div class=\"metric-row\"><span class=\"label\">Dedicated VRAM</span><span class=\"value\">'+gpu.vram_used_mb+' / '+gpu.vram_total_mb+' MB</span></div><div class=\"metric-row\"><span class=\"label\">Shared Memory</span><span class=\"value\">'+gpu.shared_used_mb+' / '+gpu.shared_total_mb+' MB</span></div>';\n"
"}\n"
"\n"
"function updAnomalies(alerts){\n"
"var d=document.getElementById('anomaly-list');\n"
"if(!alerts.length){d.innerHTML='<span style=\"color:#3fb950\">No anomalies detected</span>';return}\n"
"d.innerHTML='';var icons={cpu_hog:'CPU',mem_hog:'MEM',mem_leak:'LEAK',gpu_hog:'GPU',suspicious:'SUSP'},colors={cpu_hog:'#f85149',mem_hog:'#d29922',mem_leak:'#f85149',gpu_hog:'#d29922',suspicious:'#f85149'};\n"
"for(var i=0;i<alerts.length;i++){var a=alerts[i],dt=new Date(a.t*1000),ts=dt.getHours().toString().padStart(2,'0')+':'+dt.getMinutes().toString().padStart(2,'0');\n"
"d.innerHTML+='<div style=\"padding:6px 0;border-bottom:1px solid #21262d;font-size:13px\"><span class=\"badge\" style=\"background:'+colors[a.type]+'33;color:'+colors[a.type]+';border:1px solid '+colors[a.type]+'\">'+(icons[a.type]||a.type)+'</span> <span style=\"color:#8b949e\">'+ts+'</span> '+a.desc+'</div>';}\n"
"}\n"
"\n"
"function updSuspicious(procs){\n"
"var tb=document.getElementById('susp-tbody');\n"
"if(!procs.length){tb.innerHTML='<tr><td colspan=\"6\" style=\"text-align:center;color:#3fb950\">No suspicious processes detected</td></tr>';return}\n"
"tb.innerHTML='';for(var i=0;i<procs.length;i++){var p=procs[i],g=p.growth_mb>0?'<span class=\"danger\">+'+p.growth_mb+' MB</span>':'unchanged',ft=new Date(p.first_seen*1000).toLocaleString();tb.innerHTML+='<tr><td>'+p.pid+'</td><td class=\"process-name\" title=\"'+p.name+'\">'+p.name+'</td><td>'+g+'</td><td class=\"warning\">'+p.peak_rate.toFixed(1)+' MB/s</td><td>'+ft+'</td><td><span class=\"badge badge-danger\">'+p.alerts+'</span></td></tr>';}\n"
"}\n"
"\n"
"document.getElementById('proc-search').addEventListener('input',function(){if(window.__lastStatus)updProcesses(window.__lastStatus.processes||[])});\n"
"setInterval(function(){countdown--;if(countdown<=0)countdown=REFRESH_INTERVAL/1000},1000);\n"
"fetchStatus();fetchHistory();fetchActions();fetchCpu();fetchGpu();fetchAnomalies();fetchSuspicious();\n"
"setInterval(fetchStatus,REFRESH_INTERVAL);setInterval(fetchHistory,60000);setInterval(fetchActions,30000);\n"
"setInterval(fetchCpu,REFRESH_INTERVAL);setInterval(fetchGpu,30000);setInterval(fetchAnomalies,30000);setInterval(fetchSuspicious,30000);\n"
"</script>\n"
"</body>\n"
"</html>\n";
